export default function tokenize(input){const tokens=[];const rawList=[];let i=0;const isWhitespace=c=>c===" "||c==="\n"||c==="\t"||c==="\r";const isDigit=c=>c>="0"&&c<="9";const push=(type,value,raw)=>{tokens.push({type,value});rawList.push(raw)};const pushError=raw=>{tokens.push({type:"error",value:raw});rawList.push(raw)};while(i<input.length){const ch=input[i];if(isWhitespace(ch)){const start=i;while(i<input.length&&isWhitespace(input[i]))i++;const raw=input.slice(start,i);push("whitespace",raw,raw);continue} if("{}[]:,".includes(ch)){push("punctuator",ch,ch);i++;continue} if(ch==='"'){const start=i;i++;let value="";let raw='"';let closed=!1;while(i<input.length){const c=input[i];if(c==="\\"){const next=input[i+1];if(next==null){raw+="\\";pushError(raw);return tokens} if(next==="u"){const hex=input.slice(i+2,i+6);raw+="\\u"+hex;if(!/^[0-9a-fA-F]{4}$/.test(hex)){pushError(raw);return tokens} value+=String.fromCharCode(parseInt(hex,16));i+=6;continue} raw+="\\"+next;value+=decodeEscape(next);i+=2;continue} if(c==='"'){raw+='"';i++;closed=!0;break} raw+=c;value+=c;i++} if(!closed){pushError(raw);return tokens} push("string",value,raw);continue} if(ch==="-"||isDigit(ch)){const start=i;if(ch==="-")i++;if(input[i]==="0"){i++}else if(isDigit(input[i])){while(isDigit(input[i]))i++}else{pushError(input.slice(start,i+1));return tokens} if(input[i]==="."){i++;if(!isDigit(input[i])){pushError(input.slice(start,i+1));return tokens} while(isDigit(input[i]))i++} if(input[i]==="e"||input[i]==="E"){i++;if(input[i]==="+"||input[i]==="-")i++;if(!isDigit(input[i])){pushError(input.slice(start,i+1));return tokens} while(isDigit(input[i]))i++} const raw=input.slice(start,i);push("number",Number(raw),raw);continue} if(input.startsWith("true",i)){push("boolean",!0,"true");i+=4;continue} if(input.startsWith("false",i)){push("boolean",!1,"false");i+=5;continue} if(input.startsWith("null",i)){push("null",null,"null");i+=4;continue} pushError(ch);i++} tokens._rawList=rawList;return tokens} function decodeEscape(ch){switch(ch){case '"':return'"';case "\\":return"\\";case "/":return"/";case "b":return"\b";case "f":return"\f";case "n":return"\n";case "r":return"\r";case "t":return"\t";default:return"\\"+ch}}
